// Recibir el error directamente del Error Trigger
const errorData = $input.first().json;

// Buscar el mensaje de error en la estructura que llega
let errorMessage = '';

// Diferentes lugares donde puede estar el mensaje
if (errorData.execution?.error?.messages?.length) {
  errorMessage = errorData.execution.error.messages[0];
} else if (errorData.execution?.error?.message) {
  errorMessage = errorData.execution.error.message;
} else if (errorData.error?.message) {
  errorMessage = errorData.error.message;
} else if (typeof errorData === 'string') {
  errorMessage = errorData;
} else {
  errorMessage = JSON.stringify(errorData);
}

// Extraer el número de teléfono del mensaje de error
// Busca una secuencia de 10 a 13 dígitos (número mexicano con código país)
let chatid = '';
const phoneMatch = errorMessage.match(/(\d{10,13})/);
if (phoneMatch) {
  chatid = phoneMatch[1];
  // Si empieza con 521, cambiar a 52
  if (chatid.startsWith('521')) {
    chatid = '52' + chatid.substring(3);
  }
}

// Si aún no hay chatid, intentar buscarlo en los parámetros del nodo que falló
if (!chatid && errorData.execution?.error?.node?.parameters) {
  const params = errorData.execution.error.node.parameters;
  // Buscar en fieldsUi.fieldValues
  if (params.fieldsUi?.fieldValues) {
    const idField = params.fieldsUi.fieldValues.find(f => f.fieldId === 'id');
    if (idField && idField.fieldValue) {
      // La expresión puede ser algo como "={{ $('extraer datos1').item.json.chatid }}"
      // Extraemos el número con otro regex si aparece en la expresión
      const exprMatch = idField.fieldValue.match(/(\d{10,13})/);
      if (exprMatch) chatid = exprMatch[1];
    }
  }
}

// Valores por defecto para la API de WhatsApp
const instancia = 'botsito';
const apikey = '7E53873CD527-4790-8641-9E98A488294F';
const urlserver = 'https://botiquin.duckdns.org';

// Mensaje amigable para el cliente
const mensajeError = `❌ *Ocurrió un problema técnico*\n\nNo pudimos procesar tu solicitud en este momento. Por favor, intenta de nuevo en unos segundos.\n\nSi el problema persiste, contacta a nuestro equipo.`;

// Log interno para depuración (opcional: enviar a Telegram el chatid extraído)
console.log('Chatid extraído:', chatid);
console.log('Mensaje de error:', errorMessage);

// Devolver los datos para enviar por WhatsApp
return [{
  json: {
    chatid: chatid,
    instancia: instancia,
    apikey: apikey,
    urlserver: urlserver,
    mensaje: mensajeError,
    debug_error: errorMessage  // para depuración, puedes quitarlo después
  }
}];
